// ae3e-plotly-panel script — scatter + quadratic regression
const fields = (data && data.series && data.series[0] && data.series[0].fields) || [];
const get = (name) => {
  const f = fields.find(x => x.name === name);
  if (!f) return [];
  const v = f.values;
  if (Array.isArray(v)) return v;
  if (v && typeof v.toArray === 'function') return v.toArray();
  return Array.from(v || []);
};

const xs = get('posts_in_month');
const ys = get('impressions');
const ids = get('id');
const dates = get('posted_date');
const types = get('type');

const n = xs.length;

// Quadratic fit: solve normal equations for y = a + b*x + c*x^2
let S0 = n, S1 = 0, S2 = 0, S3 = 0, S4 = 0;
let T0 = 0, T1 = 0, T2 = 0;
for (let i = 0; i < n; i++) {
  const x = xs[i], y = ys[i];
  const x2 = x * x;
  S1 += x; S2 += x2; S3 += x2 * x; S4 += x2 * x2;
  T0 += y; T1 += x * y; T2 += x2 * y;
}

// Gaussian elimination on the 3x3 augmented matrix [S | T]
const M = [
  [S0, S1, S2, T0],
  [S1, S2, S3, T1],
  [S2, S3, S4, T2]
];
for (let i = 0; i < 3; i++) {
  let maxRow = i;
  for (let k = i + 1; k < 3; k++) if (Math.abs(M[k][i]) > Math.abs(M[maxRow][i])) maxRow = k;
  [M[i], M[maxRow]] = [M[maxRow], M[i]];
  for (let k = i + 1; k < 3; k++) {
    const factor = M[i][i] ? M[k][i] / M[i][i] : 0;
    for (let j = i; j < 4; j++) M[k][j] -= factor * M[i][j];
  }
}
const c = M[2][2] ? M[2][3] / M[2][2] : 0;
const b = M[1][1] ? (M[1][3] - M[1][2] * c) / M[1][1] : 0;
const a = M[0][0] ? (M[0][3] - M[0][1] * b - M[0][2] * c) / M[0][0] : 0;

// R^2
const meanY = n ? T0 / n : 0;
let ssRes = 0, ssTot = 0;
for (let i = 0; i < n; i++) {
  const pred = a + b * xs[i] + c * xs[i] * xs[i];
  ssRes += (ys[i] - pred) ** 2;
  ssTot += (ys[i] - meanY) ** 2;
}
const r2 = ssTot ? 1 - ssRes / ssTot : 0;

// Smooth curve across the x range
const xMin = xs.length ? Math.min(...xs) : 0;
const xMax = xs.length ? Math.max(...xs) : 1;
const steps = 50;
const curveX = [], curveY = [];
for (let i = 0; i <= steps; i++) {
  const x = xMin + (xMax - xMin) * i / steps;
  curveX.push(x);
  curveY.push(a + b * x + c * x * x);
}

return {
  data: [
    {
      x: xs, y: ys, mode: 'markers', type: 'scatter', name: 'Posts',
      text: ids.map((id, i) => (dates[i] || '') + ' • ' + (types[i] || '') + ' • id=' + id),
      hovertemplate: 'Posts in month: %{x}<br>Impressions: %{y:,}<br>%{text}<extra></extra>',
      marker: { size: 10, color: '#5794f2', opacity: 0.75, line: { width: 1, color: '#3a6dbf' } }
    },
    {
      x: curveX, y: curveY,
      mode: 'lines', type: 'scatter',
      name: 'Quadratic fit (R²=' + r2.toFixed(2) + ')',
      line: { color: '#ff7f0e', width: 2, dash: 'dash' }
    }
  ],
  layout: {
    xaxis: { title: { text: 'Posts published that month' }, gridcolor: '#444', dtick: 1 },
    yaxis: { title: { text: 'Impressions (latest snapshot)' }, gridcolor: '#444' },
    showlegend: true,
    legend: { orientation: 'h', y: -0.2, x: 0 },
    plot_bgcolor: 'rgba(0,0,0,0)', paper_bgcolor: 'rgba(0,0,0,0)',
    font: { color: '#ccc' },
    margin: { l: 60, r: 20, t: 20, b: 80 }
  }
};

// ae3e-plotly-panel script — impressions per post over time + median (L1) fit + bootstrap band
const fields = (data && data.series && data.series[0] && data.series[0].fields) || [];
const get = (name) => {
  const f = fields.find(x => x.name === name);
  if (!f) return [];
  const v = f.values;
  if (Array.isArray(v)) return v;
  if (v && typeof v.toArray === 'function') return v.toArray();
  return Array.from(v || []);
};

const dates = get('posted_date');
const ysAll = get('impressions');
const idsAll = get('id');
const typesAll = get('type');
const ppmAll = get('posts_in_month');

// Center x for numerical stability — use days since the earliest post
const day = 86400000;
const toMs = (d) => new Date(d + 'T00:00:00Z').getTime();
const msAll = dates.map(toMs);
const tMin = Math.min(...msAll);
const tMax = Math.max(...msAll);

// Drop rows without a numeric Y (defensive; correlation_points should already be clean)
const xs = [], ys = [], rowDates = [], rowIds = [], rowTypes = [], rowPpm = [];
for (let i = 0; i < dates.length; i++) {
  if (typeof ysAll[i] !== 'number' || !isFinite(ysAll[i])) continue;
  xs.push((msAll[i] - tMin) / day);
  ys.push(ysAll[i]);
  rowDates.push(dates[i]);
  rowIds.push(idsAll[i]);
  rowTypes.push(typesAll[i]);
  rowPpm.push(ppmAll[i]);
}
const n = xs.length;

// --- IRLS median (L1) regression -------------------------------------------
function l1Fit(xs, ys, iters, eps) {
  const n = xs.length;
  if (n < 2) return [n ? (ys[0] || 0) : 0, 0];
  let sX = 0, sY = 0, sXY = 0, sX2 = 0;
  for (let i = 0; i < n; i++) {
    sX += xs[i]; sY += ys[i];
    sXY += xs[i] * ys[i]; sX2 += xs[i] * xs[i];
  }
  const den = n * sX2 - sX * sX;
  let b = den ? (n * sXY - sX * sY) / den : 0;
  let a = (sY - b * sX) / n;
  for (let iter = 0; iter < iters; iter++) {
    let w = 0, wx = 0, wy = 0, wxx = 0, wxy = 0;
    for (let i = 0; i < n; i++) {
      const r = Math.abs(ys[i] - (a + b * xs[i]));
      const wi = 1 / Math.max(r, eps);
      w += wi; wx += wi * xs[i]; wy += wi * ys[i];
      wxx += wi * xs[i] * xs[i]; wxy += wi * xs[i] * ys[i];
    }
    const d = w * wxx - wx * wx;
    if (!d) break;
    const newB = (w * wxy - wx * wy) / d;
    const newA = (wy - newB * wx) / w;
    if (Math.abs(newA - a) < 1e-6 && Math.abs(newB - b) < 1e-6) { a = newA; b = newB; break; }
    a = newA; b = newB;
  }
  return [a, b];
}

const [a, b] = l1Fit(xs, ys, 50, 1e-6);

// Pseudo-R^2 for L1: 1 - sum|y - yhat| / sum|y - median(y)|
const sortedY = [...ys].sort((p, q) => p - q);
const medY = sortedY.length % 2
  ? sortedY[(sortedY.length - 1) >> 1]
  : 0.5 * (sortedY[sortedY.length / 2 - 1] + sortedY[sortedY.length / 2]);
let sumDevFit = 0, sumDevNull = 0;
for (let i = 0; i < n; i++) {
  sumDevFit += Math.abs(ys[i] - (a + b * xs[i]));
  sumDevNull += Math.abs(ys[i] - medY);
}
const r1 = sumDevNull ? 1 - sumDevFit / sumDevNull : 0;

// --- Bootstrap band (B resamples, percentile band at curve nodes) ----------
const STEPS = 40, B = 200;
const xMaxN = (tMax - tMin) / day;
const curveXn = [];
for (let i = 0; i <= STEPS; i++) curveXn.push(xMaxN * i / STEPS);

// Deterministic LCG seeded by N so the band stops shimmering on every refresh
let seed = 1234567 + n * 31;
const rand = () => { seed = (seed * 1664525 + 1013904223) & 0x7fffffff; return seed / 0x7fffffff; };

const bootCurves = [];
for (let bi = 0; bi < B; bi++) {
  const bxs = new Array(n), bys = new Array(n);
  for (let i = 0; i < n; i++) {
    const k = Math.floor(rand() * n);
    bxs[i] = xs[k]; bys[i] = ys[k];
  }
  const [ba, bb] = l1Fit(bxs, bys, 25, 1e-6);
  bootCurves.push(curveXn.map(x => ba + bb * x));
}
const lo = [], hi = [];
for (let i = 0; i < curveXn.length; i++) {
  const col = bootCurves.map(c => c[i]).sort((p, q) => p - q);
  lo.push(col[Math.floor(0.025 * B)]);
  hi.push(col[Math.floor(0.975 * B)]);
}
const median = curveXn.map(x => a + b * x);

const fromMs = (t) => new Date(t).toISOString().slice(0, 10);
const curveX = curveXn.map(x => fromMs(tMin + x * day));
const monthlyDelta = b * 30;

return {
  data: [
    // Bootstrap band: upper edge (invisible line), then lower edge filled toward it
    {
      x: curveX, y: hi, type: 'scatter', mode: 'lines',
      line: { width: 0 }, hoverinfo: 'skip', showlegend: false
    },
    {
      x: curveX, y: lo, type: 'scatter', mode: 'lines',
      line: { width: 0 }, fill: 'tonexty',
      fillcolor: 'rgba(255, 127, 14, 0.18)',
      name: '95% bootstrap band', hoverinfo: 'skip'
    },
    // Raw points
    {
      x: rowDates, y: ys, mode: 'markers', type: 'scatter', name: 'Posts',
      text: rowIds.map((id, i) => (rowTypes[i] || '') + ' • posts/mo: ' + (rowPpm[i] != null ? rowPpm[i] : '') + ' • id=' + id),
      hovertemplate: '%{x}<br>Impressions: %{y:,}<br>%{text}<extra></extra>',
      marker: { size: 10, color: '#5794f2', opacity: 0.75, line: { width: 1, color: '#3a6dbf' } }
    },
    // Median (L1) fit line
    {
      x: curveX, y: median, mode: 'lines', type: 'scatter',
      name: 'Median fit (pseudo-R²=' + r1.toFixed(2) + ', ' + (monthlyDelta >= 0 ? '+' : '') + monthlyDelta.toFixed(0) + ' impr/30d, 95% boot band)',
      line: { color: '#ff7f0e', width: 2, dash: 'dash' }
    }
  ],
  layout: {
    xaxis: { title: { text: 'Date posted' }, gridcolor: '#444', type: 'date' },
    yaxis: { title: { text: 'Impressions (latest snapshot)' }, gridcolor: '#444' },
    showlegend: true,
    legend: { orientation: 'h', y: -0.2, x: 0 },
    plot_bgcolor: 'rgba(0,0,0,0)', paper_bgcolor: 'rgba(0,0,0,0)',
    font: { color: '#ccc' },
    margin: { l: 60, r: 20, t: 20, b: 80 }
  }
};
